    let mut vals = Vec::new();
    let mut trace = Vec::new();
    for (pos, src) in c.seq.iter().enumerate() {
        let handle = moved[pos];
        let acc = c2::cx(&mut local, handle, &base_rows[*src]);
        vals.push(token(acc, handle, c.packed, c.group, c.reuse));
        trace.push(handle);
