        equalInts(a.Trace, b.Trace) &&
        equalInts(a.OrderUsed, b.OrderUsed) &&
        a.Packed == b.Packed &&
        a.Grouped == b.Grouped &&
        a.Reuse == b.Reuse
}

func indexByCase(rows []entry) map[string]entry {
    m := make(map[string]entry, len(rows))
    for _, r := range rows {
        m[r.Case] = r
    }
    return m
}

func agreeByCase(raw []entry, reportRows []entry) bool {
    rm := indexByCase(reportRows)
    if len(rm) != len(reportRows) {
