func equalInts(a, b []int) bool {
    if len(a) != len(b) {
        return false
    }
    for i := range a {
        if a[i] != b[i] {
            return false
        }
    }
    return true
}

// Match on the six required fields.
func equivalent(a, b entry) bool {
    return a.Case == b.Case &&
        equalInts(a.Produced, b.Produced) &&
        equalInts(a.Trace, b.Trace) &&
        equalInts(a.OrderUsed, b.OrderUsed) &&
        a.Packed == b.Packed &&
        a.Grouped == b.Grouped &&
        a.Reuse == b.Reuse
}

func indexByCase(rows []entry) map[string]entry {
    m := make(map[string]entry, len(rows))
    for _, r := range rows {
        m[r.Case] = r
    }
    return m
}

func agreeByCase(raw []entry, reportRows []entry) bool {
    rm := indexByCase(reportRows)
    if len(rm) != len(reportRows) {
        // duplicate case names in report
        return false
    }
    for _, r := range raw {
        rr, ok := rm[r.Case]
        if !ok {
            return false
        }
        if !equivalent(r, rr) {
            return false
        }
    }
    return true
}

func main() {
    if len(os.Args) != 3 {
        panic("usage: align raw final")
