    var raw rawDoc
    if err := json.Unmarshal(buf, &raw); err != nil {
        panic(err)
    }

    // One row per built-in case: keep all raw rows (no dropping/merging).
    rows := append([]entry{}, raw.Raw...)
    sort.Slice(rows, func(i, j int) bool { return rows[i].Case < rows[j].Case })

    // agree requires:
    //  (1) rows we are writing match incoming raw on the six fields per case name
    //  (2) if replacing an existing report.json, prior report rows must also match incoming raw
    agree := agreeByCase(raw.Raw, rows)

    if priorBuf, err := os.ReadFile(finalPath); err == nil {
        var prior finalDoc
        if err := json.Unmarshal(priorBuf, &prior); err == nil {
            if !agreeByCase(raw.Raw, prior.Rows) {
                agree = false
            }
        } else {
            // If prior report exists but is unreadable, treat as mismatch.
            agree = false
        }
    }

    doc := finalDoc{Rows: rows, Summary: map[string]any{"total": len(raw.Raw), "agree": agree}}
    out, err := json.MarshalIndent(doc, "", "  ")
    if err != nil {
