package main

import (
    "encoding/json"
    "os"
    "sort"
)

type entry struct {
    Case      string `json:"case"`
    Produced  []int  `json:"produced"`
    Trace     []int  `json:"slot_trace"`
    OrderUsed []int  `json:"order_used"`
    Packed    bool   `json:"packed"`
    Grouped   bool   `json:"grouped"`
    Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
    Raw []entry `json:"raw"`
}

type finalDoc struct {
    Rows    []entry        `json:"rows"`
    Summary map[string]any `json:"summary"`
}

func equalInts(a, b []int) bool {
    if len(a) != len(b) {
        return false
    }
    for i := range a {
        if a[i] != b[i] {
            return false
        }
    }
    return true
}

// Match on the six required fields.
func equivalent(a, b entry) bool {
    return a.Case == b.Case &&
        equalInts(a.Produced, b.Produced) &&
        equalInts(a.Trace, b.Trace) &&
        equalInts(a.OrderUsed, b.OrderUsed) &&
        a.Packed == b.Packed &&
        a.Grouped == b.Grouped &&
        a.Reuse == b.Reuse
}

func indexByCase(rows []entry) map[string]entry {
    m := make(map[string]entry, len(rows))
    for _, r := range rows {
        m[r.Case] = r
    }
    return m
}

func agreeByCase(raw []entry, reportRows []entry) bool {
    rm := indexByCase(reportRows)
    if len(rm) != len(reportRows) {
        // duplicate case names in report
        return false
    }
    for _, r := range raw {
        rr, ok := rm[r.Case]
        if !ok {
            return false
        }
        if !equivalent(r, rr) {
            return false
        }
    }
    return true
}

func main() {
    if len(os.Args) != 3 {
        panic("usage: align raw final")
    }

    rawPath := os.Args[1]
    finalPath := os.Args[2]

    buf, err := os.ReadFile(rawPath)
    if err != nil {
        panic(err)
    }
    var raw rawDoc
    if err := json.Unmarshal(buf, &raw); err != nil {
        panic(err)
    }

    // One row per built-in case: keep all raw rows (no dropping/merging).
    rows := append([]entry{}, raw.Raw...)
    sort.Slice(rows, func(i, j int) bool { return rows[i].Case < rows[j].Case })

    // agree requires:
    //  (1) rows we are writing match incoming raw on the six fields per case name
    //  (2) if replacing an existing report.json, prior report rows must also match incoming raw
    agree := agreeByCase(raw.Raw, rows)

    if priorBuf, err := os.ReadFile(finalPath); err == nil {
        var prior finalDoc
        if err := json.Unmarshal(priorBuf, &prior); err == nil {
            if !agreeByCase(raw.Raw, prior.Rows) {
                agree = false
            }
        } else {
            // If prior report exists but is unreadable, treat as mismatch.
            agree = false
        }
    }

    doc := finalDoc{Rows: rows, Summary: map[string]any{"total": len(raw.Raw), "agree": agree}}
    out, err := json.MarshalIndent(doc, "", "  ")
    if err != nil {
        panic(err)
    }
    if err := os.WriteFile(finalPath, append(out, '\n'), 0o644); err != nil {
        panic(err)
    }
}
